// Создаем индекс шаблонов по сценариям
const CT = config.COLUMNS.TEMPLATES;
const templatesByScenario = new Map();

templateRows.forEach(t => {
  const scenario = t.json[CT.SCENARIO];
  if (scenario) {
    // Сохраняем первый найденный шаблон для каждого сценария
    if (!templatesByScenario.has(scenario)) {
      templatesByScenario.set(scenario, {
        frdoDocType: t.json[CT.FRDO_DOC_TYPE] || "",
        frdoExtraProgram: t.json[CT.FRDO_EXTRA_PROGRAM] || ""
      });
    }
  }
});

console.log(`Создан индекс шаблонов для ${templatesByScenario.size} сценариев`);

// Готовим задачи
const tasks = [];
const C = config.COLUMNS.REGISTRY;

registryRows.forEach((item, index) => {
  const reg = item.json;
  const id = reg[C.ID];
  const scenario = reg[C.SCENARIO];

  // Проверяем обязательные поля
  if (!id) {
    return;
  }

  // Рассчитываем период обучения для данной заявки
  const period = calculateStudyPeriod(reg);

  // Обработка гражданства
  let citizenship = "643"; // По умолчанию Россия
  const citizenshipValue = reg[C.CITIZENSHIP];
  if (citizenshipValue && citizenshipValue.trim() !== "") {
    const parts = citizenshipValue.split(":");
    if (parts.length > 1) {
      citizenship = parts[1].trim();
    }
  }

  // Разбор ФИО
  const fio = splitFIO(reg[C.FULL_NAME] || "");

  // FRDO_DOC_NUM - только для сценариев с "Диплом"
  let frdoDocNum = "";
  if (scenario && scenario.includes("Диплом")) {
    frdoDocNum = reg[C.FRDO_DOC_NUM] || "";
  } else if (scenario && scenario.includes("Удостоверение")) {
    frdoDocNum = "Нет";
  }

  // Получаем данные из шаблонов по сценарию
  const templateData = templatesByScenario.get(scenario) || {
    frdoDocType: "",
    frdoExtraProgram: ""
  };

  // Формируем данные записи
  const recordData = {
    id,
    scenario: scenario || null,
    citizenship,
    birthDate: reg[C.BIRTH_DATE] || "",
    gender: reg[C.GENDER] || "",
    program: reg[C.PROGRAM] || "",
    regNumber: reg[C.REG_NUMBER].split(":")[1] || "",
    snils: reg[C.SNILS] || "",
    surname: fio.surname,
    name: fio.name,
    qualif: reg[C.QUALIFICATION] || "Нет",
    patronymic: fio.patronymic,
    frdoDocNum,
    hours: reg[C.HOURS] || "",
    frdoDocType: templateData.frdoDocType,
    frdoExtraProgram: templateData.frdoExtraProgram,
    period: {
      startYear: period.startYear,
      endYear: period.endYear,
      dateFull: period.dateFull
    },
  };

  // Проверяем заполненность полей
  const missingFields = validateFields(recordData);

  if (missingFields.length === 0) {
    // Все обязательные поля заполнены
    recordData.status = "toFrdoTable";
    console.log(`✅ ID=${id}: Все поля заполнены`);
  } else {
    // Есть незаполненные обязательные поля
    recordData.status = "incomplete";
    recordData.missingFields = missingFields;
    console.log(`⚠️ ID=${id}: Не заполнены поля: ${missingFields.join(', ')}`);
  }

  // Добавляем задачу
  tasks.push({
    json: recordData
  });
});

console.log(`\n=== ИТОГО ===`);
console.log(`Подготовлено записей: ${tasks.length}`);
